const express = require('express');
const axios = require('axios');

const app = express();
app.use(express.json());

const PORT = process.env.PORT || 3000;
const PREMBLY_BASE_URL = process.env.PREMBLY_BASE_URL || 'https://api.prembly.com';
const PREMBLY_APP_ID = process.env.PREMBLY_APP_ID;
const PREMBLY_API_KEY = process.env.PREMBLY_API_KEY;

const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

app.post('/verify-nin', async (req, res) => {
  const { nin } = req.body;

  if (!nin) {
    return res.status(400).json({ error: 'NIN is required' });
  }

  const maxRetries = 3;
  const backoffTimes = [100, 200, 400];

  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      const response = await axios.post(
        `${PREMBLY_BASE_URL}/verification/nin`,
        { nin },
        {
          headers: {
            'app-id': PREMBLY_APP_ID,
            'x-api-key': PREMBLY_API_KEY,
          },
        }
      );

      return res.status(200).json(response.data);
    } catch (error) {
      if (error.response && error.response.status === 429 && attempt < maxRetries) {
        console.log(`Rate limited. Retrying in ${backoffTimes[attempt]}ms... (Attempt ${attempt + 1})`);
        await sleep(backoffTimes[attempt]);
        continue;
      }

      if (error.response && error.response.status === 429) {
        return res.status(429).json({ message: 'Rate limit exceeded, please try again later' });
      }

      const status = error.response ? error.response.status : 500;
      const data = error.response ? error.response.data : { message: 'Internal Server Error' };
      return res.status(status).json(data);
    }
  }
});

app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});

